module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green,
    output [7:0] clock
);

    reg [7:0] timer;
    reg [1:0] state;
    parameter IDLE = 2'b00, GREEN = 2'b01, YELLOW = 2'b10, RED = 2'b11;

    assign clock = timer;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
            timer <= 0;
            red <= 0;
            yellow <= 0;
            green <= 1;
        end else begin
            case (state)
                IDLE: begin
                    if (pass_request) begin
                        state <= RED;
                        timer <= 8'd10;
                    end else begin
                        state <= GREEN;
                        timer <= 8'd60;
                    end
                    red <= 0;
                    yellow <= 0;
                    green <= 1;
                end
                GREEN: begin
                    if (timer == 8'd10) begin
                        state <= YELLOW;
                        timer <= 8'd5;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 0;
                    yellow <= 0;
                    green <= 1;
                end
                YELLOW: begin
                    if (timer == 8'd5) begin
                        state <= RED;
                        timer <= 8'd10;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 0;
                    yellow <= 1;
                    green <= 0;
                end
                RED: begin
                    if (timer == 8'd10) begin
                        state <= GREEN;
                        timer <= 8'd60;
                    end else begin
                        timer <= timer - 1;
                    end
                    red <= 1;
                    yellow <= 0;
                    green <= 0;
                end
            endcase
        end
    end

endmodule
